results.candidate_sql:
SELECT COUNT(*) 
FROM frpm 
WHERE "County Name" = 'Amador' AND "Low Grade" = '9' AND "High Grade" = '12';

SELECT sname, cname 
FROM (
    SELECT *, ROW_NUMBER() OVER (ORDER BY NumGE1500 DESC) AS rn 
    FROM satscores
) AS t 
WHERE rn = 1;

SELECT NCESDist 
FROM schools 
WHERE SOC = '31' AND NOT StatusType IS NULL;

SELECT 
    ROUND(
        (
            SUM(CASE WHEN status = 'A' THEN amount ELSE 0 END)::float 
            / 
            NULLIF(SUM(amount), 0)
        ) * 100, 
        2
    ) AS percentage_fully_paid
FROM loan;

SELECT DISTINCT a.account_id
FROM account a
WHERE a.frequency = 'POPLATEK MESICNE';

SELECT (SUM(CASE WHEN district.A3 = 'North Bohemia' THEN district.A16 ELSE 0 END) - 
        SUM(CASE WHEN district.A3 = 'East Bohemia' THEN district.A16 ELSE 0 END)) AS crime_difference
FROM district;

SELECT ROUND(
    (COUNT(CASE WHEN c.gender = 'M' AND a.frequency = 'POPLATEK TYDNE' THEN 1 END) * 100.0 / 
     COUNT(CASE WHEN a.frequency = 'POPLATEK TYDNE' THEN 1 END)), 2
)
FROM account a
JOIN client c ON a.district_id = c.district_id;

SELECT AVG(o_count) FROM (
  SELECT molecule_id, COUNT(*) as o_count 
  FROM atom 
  WHERE element = 'O' AND molecule_id IN (
    SELECT molecule_id 
    FROM bond 
    WHERE bond_type = '-'
  )
  GROUP BY molecule_id
) t;

SELECT COUNT(DISTINCT a.atom_id)
FROM atom a
WHERE a.element != 'Br';

SELECT c.bond_id 
FROM connected c, atom a 
WHERE a.atom_id = 'TR000_2' AND c.atom_id2 = a.atom_id;

SELECT ROUND(
  (CAST(COUNT(CASE WHEN label = '+' THEN 1 END) AS FLOAT) / 
   CAST(COUNT(*) AS FLOAT)) * 100, 
  3
)
FROM molecule;

SELECT ROUND(CAST((COUNT(CASE WHEN a.element = 'h' THEN 1 END) * 100.0) AS DECIMAL(5,4)) / COUNT(*), 4) as percentage 
FROM atom a 
WHERE molecule_id = 'TR206';

SELECT COUNT(*) 
FROM atom 
WHERE element IN ('C', 'H');

SELECT DISTINCT m.molecule_id 
FROM molecule m 
WHERE m.label = '-';

SELECT CASE WHEN label = '+' THEN 'Yes' ELSE 'No' END AS is_carcinogenic 
FROM molecule 
WHERE molecule_id = 'TR124';

SELECT element 
FROM atom 
WHERE atom_id = 'TR000_1';

SELECT ROUND(
  (COUNT(CASE WHEN f.language = 'Chinese Simplified' THEN 1 END) / 
   COUNT(DISTINCT c.id)) * 100, 2
)
FROM cards c
JOIN foreign_data f ON c.uuid = f.uuid;

SELECT COUNT(*) 
FROM cards 
WHERE originalType = 'Summon - Angel' AND subtypes != 'Angel';

SELECT COUNT(*) 
FROM cards 
WHERE frameVersion LIKE '%1993%' AND availability = 'paper' AND hasContentWarning = 1;

SELECT SUM(CAST(REPLACE(SUBSTRING(manaCost, 1, LENGTH(manaCost) - 1), '{', '') AS REAL))
FROM cards 
WHERE artist = 'Rob Alexander';

SELECT ROUND(
  (COUNT(CASE WHEN isOnlineOnly = 1 THEN id END) * 100.0 / NULLIF(COUNT(id), 0)),
  2
)
FROM cards 
WHERE frameEffects LIKE '%legendary%';

SELECT c.name 
FROM cards c 
WHERE c.borderColor = 'black' AND c.isFullArt = 1;

SELECT DISTINCT s.baseSetSize, s.code 
FROM sets s 
WHERE s.block IN ('Masques', 'Mirage');

SELECT COUNT(*) 
FROM cards 
WHERE availability LIKE '%paper%' AND hand = '3';

SELECT artist 
FROM cards 
WHERE flavorName = 'Battra, Dark Destroyer';

SELECT (COUNT(CASE WHEN cardKingdomFoilId IS NOT NULL AND cardKingdomId IS NOT NULL THEN 1 END) * 100.0 / COUNT(*)) AS percentage 
FROM cards 
WHERE setCode = 'CSP';

SELECT DISTINCT availability 
FROM cards 
WHERE artist != 'Aleksi Briclot' AND isTextless = 1;

SELECT DisplayName 
FROM users 
WHERE YEAR(CAST(STRFTIME('%Y-%m-%d', CreationDate) AS DATE)) = 2011;

SELECT COUNT(*) 
FROM votes 
WHERE UserId = 58 AND CreationDate = '2010-07-19';

SELECT ViewCount 
FROM posts 
WHERE Title = 'Integration of Weka and/or RapidMiner into Informatica PowerCenter/Developer';

SELECT Text 
FROM comments 
WHERE Score = 17;

SELECT c.Text FROM comments c 
JOIN posts p ON c.PostId = p.Id 
WHERE p.Title = 'Why square the difference instead of taking the absolute value in standard deviation?';

SELECT COUNT(DISTINCT Id) 
FROM users 
WHERE LOWER(Location) LIKE '%new york%';

SELECT DisplayName, Views 
FROM users 
ORDER BY Views DESC;

SELECT 
  CAST(
    COUNT(CASE WHEN p.Tags LIKE '%r%' THEN 1 END) AS FLOAT
  ) /
  NULLIF(
    (SELECT COUNT(*) FROM posts WHERE OwnerDisplayName = 'Community'), 
    0
  ) * 100 as percentage
FROM posts p;

SELECT COUNT(*) 
FROM users 
WHERE Reputation > 2000 AND Views > 1000;

SELECT COUNT(*) FROM (
  SELECT Id, ViewCount 
  FROM posts 
  WHERE ViewCount > (SELECT AVG(CAST(ViewCount AS FLOAT)) FROM posts)
) sub;

SELECT COUNT(*) 
FROM posts 
WHERE ViewCount > 35000 AND CommentCount = 0;

SELECT COUNT(DISTINCT UserId) 
FROM badges 
WHERE Name = 'Citizen Patrol';

SELECT COUNT(*) 
FROM tags 
WHERE Id < 15 AND Count <= 20;

SELECT ExcerptPostId, WikiPostId 
FROM tags 
WHERE TagName = 'sample';

SELECT r.race FROM superhero s 
JOIN race r ON s.race_id = r.id 
WHERE s.superhero_name = 'Copycat';

SELECT 
    (SELECT weight_kg FROM superhero WHERE full_name = 'Emil Blonsky') -
    (SELECT weight_kg FROM superhero WHERE full_name = 'Charles Chandler');

SELECT ROUND(100.0 * (COUNT(CASE WHEN c.colour = 'Blue' THEN 1 END) / COUNT(*)), 2) 
FROM superhero s 
JOIN colour c ON s.eye_colour_id = c.id;

SELECT superhero_name 
FROM superhero 
WHERE full_name = 'Charles Chandler';

SELECT (COUNT(CASE WHEN g.gender = 'Female' THEN 1 END) * 100.0 / COUNT(*)) AS percentage_female 
FROM superhero s 
JOIN gender g ON s.gender_id = g.id 
WHERE s.publisher_id IN (
    SELECT id FROM publisher WHERE publisher_name = 'George Lucas'
);

SELECT ha.attribute_value FROM hero_attribute ha 
JOIN superhero sh ON ha.hero_id = sh.id 
WHERE sh.superhero_name = 'Aquababy';

SELECT nationality 
FROM drivers 
WHERE dob = (SELECT MIN(dob) FROM drivers);

SELECT CAST(
    COUNT(DISTINCT r.resultId) AS FLOAT
) / NULLIF(
    (SELECT COUNT(*) FROM results WHERE raceId = 2008),
    0
) as completion_rate
FROM results r
WHERE r.raceId = 2008 
AND r.time IS NOT NULL;

SELECT COUNT(*) 
FROM circuits 
WHERE location = 'Adelaide' AND country = 'Australia';

SELECT COUNT(DISTINCT r.driverId)
FROM results r
WHERE r.raceId = 18;

SELECT AVG(race_count) FROM (
    SELECT year, COUNT(*) as race_count 
    FROM races 
    WHERE date >= '2000-01-01' AND date <= '2010-12-31'
    GROUP BY year
);

SELECT SUM(wins) FROM (
    SELECT cs.wins 
    FROM constructorStandings cs
    JOIN driverStandings ds ON cs.raceId = ds.raceId AND cs.position = 91
    GROUP BY cs.constructorId, cs.raceId
) AS wins;

SELECT MIN(fastestLapTime) AS fastest_lap_time 
FROM results 
WHERE fastestLap = 1;

SELECT 
    (SELECT AVG(ball_control) FROM Player_Attributes pa JOIN Player p ON pa.player_api_id = p.id WHERE p.player_name = 'Abdou Diallo') -
    (SELECT AVG(ball_control) FROM Player_Attributes pa JOIN Player p ON pa.player_api_id = p.id WHERE p.player_name = 'Aaron Appindangoye');

SELECT CAST(
  (
    SELECT COUNT(*) 
    FROM Patient 
    WHERE YEAR(Birthday) > 1930 AND Sex = 'F'
  ) AS FLOAT
) / COUNT(*)
FROM Patient
WHERE Sex = 'F';

SELECT (COUNT(CASE WHEN Admission = '+' THEN 1 END) * 100.0) / COUNT(*) AS percentage_inpatient
FROM Patient
WHERE Birthday BETWEEN '1930-01-01' AND '1940-12-31';

SELECT (CAST(COUNT(DISTINCT CASE WHEN p.SEX = 'F' AND (l.TP < 6.0 OR l.TP > 8.5) THEN l.ID END) AS REAL) / CAST(COUNT(DISTINCT CASE WHEN p.SEX = 'F' THEN l.ID END) AS REAL)) * 100 AS percentage 
FROM Laboratory l
JOIN Patient p ON l.ID = p.ID;

SELECT 
    CAST(
        (SELECT COUNT(*) FROM Patient p JOIN Laboratory l ON p.ID = l.ID WHERE l.UA <= 8.0 AND p.SEX = 'M') AS REAL
    ) / 
    NULLIF(
        (SELECT COUNT(*) FROM Patient p JOIN Laboratory l ON p.ID = l.ID WHERE l.UA <= 6.5 AND p.SEX = 'F'),
        0
    ) AS male_to_female_ratio;

SELECT CAST((COUNT(CASE WHEN Diagnosis = 'BEHCET' THEN 1 END) * 100.0) / COUNT(*) AS REAL)
FROM Patient 
WHERE SEX = 'M' AND YEAR(`First Date`) = 1981;

SELECT (COUNT(CASE WHEN p.SEX = 'F' THEN 1 END) * 100.0 / COUNT(*)) AS percentage_women 
FROM Patient p 
WHERE YEAR(p.Birthday) = 1980 AND p.Diagnosis = 'RA';

SELECT Date 
FROM Laboratory 
WHERE ID = '48473' AND GOT >= 60;

SELECT AVG(HCT) AS avg_hematocrit
FROM Laboratory 
WHERE Date LIKE '1991%' AND HCT < 29;

SELECT (COUNT(DISTINCT CASE WHEN l.GOT >= 60 AND p.Diagnosis = 'SLE' THEN l.ID END) * 100.0 / COUNT(DISTINCT CASE WHEN l.GOT >= 60 THEN l.ID END)) as percentage
FROM Laboratory l
JOIN Patient p ON l.ID = p.ID;

SELECT 
    CASE 
        WHEN (
            SELECT amount FROM budget WHERE link_to_event IN (SELECT event_id FROM event WHERE event_name = 'Yearly Kickoff') AND category = 'Advertisement'
        ) > (
            SELECT amount FROM budget WHERE link_to_event IN (SELECT event_id FROM event WHERE event_name = 'October Meeting') AND category = 'Advertisement'
        ) THEN 1
    END AS advertisement_budget_difference;

SELECT COUNT(DISTINCT city) 
FROM zip_code 
WHERE county = 'Orange' AND state = 'Virginia';

SELECT COUNT(*) 
FROM member 
WHERE position = 'President';

SELECT m.first_name || ' ' || m.last_name AS full_name, m.email 
FROM member m 
WHERE m.position = 'Secretary';

SELECT MAX(budget.amount)
FROM budget
WHERE budget.category = 'Food';

SELECT 
    (COUNT(CASE WHEN m.link_to_major IN (
        SELECT major_id FROM major WHERE major_name = 'Business'
    ) THEN member_id END) / COUNT(member_id)) * 100 AS percentage
FROM member m;

SELECT DISTINCT state 
FROM zip_code 
WHERE type = 'PO Box';

SELECT zip_code 
FROM zip_code 
WHERE county = 'San Juan Municipio' AND state = 'Puerto Rico' AND type = 'PO Box';

SELECT (COUNT(CASE WHEN b.remaining < 0 THEN 1 END) * 100.0 / COUNT(e.event_id)) AS over_budget_percentage
FROM event e
LEFT JOIN budget b ON e.event_id = b.link_to_event;

SELECT event_id, location, status 
FROM event 
WHERE event_date BETWEEN '2019-11-01' AND '2020-03-31';

SELECT ROUND((COUNT(CASE WHEN Currency = 'EUR' THEN CustomerID END) * 100.0) / COUNT(*), 2) 
FROM customers 
WHERE Segment = 'KAM';

SELECT ROUND(CAST(SUM(CASE WHEN g.Segment = 'Premium' THEN 1 ELSE 0 END) AS FLOAT) * 100.0 / COUNT(*), 2)
FROM gasstations g
WHERE g.Country = 'Slovakia';

SELECT MAX(Consumption) 
FROM yearmonth 
WHERE Date LIKE '2012%';
